package org.eclipse.rdf4j.query.parser.sparql.manifest;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotSame;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.atomic.AtomicReference;

import org.eclipse.rdf4j.query.algebra.QueryModelNode;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.Test;

class TupleExprJsonOptimizerRoundTripHarnessTest {

	@Test
	void feedsEachOptimizerNodesCreatedByThePreviousImport() {
		QueryRoot root = new QueryRoot(new StatementPattern(new Var("s"), new Var("p"), new Var("o")));
		QueryModelNode originalChild = root.getArg();
		AtomicReference<QueryModelNode> firstOptimizerInput = new AtomicReference<>();
		AtomicReference<QueryModelNode> secondOptimizerInput = new AtomicReference<>();
		List<QueryModelNode> importedChildren = new ArrayList<>();

		List<TupleExprJsonOptimizerRoundTripHarness.Stage> stages = List.of(
				new TupleExprJsonOptimizerRoundTripHarness.Stage("first fake", (tupleExpr, dataset, bindings) -> {
					assertNotSame(originalChild, root.getArg());
					firstOptimizerInput.set(root.getArg());
					root.getArg().setOptimizationTag(101);
				}),
				new TupleExprJsonOptimizerRoundTripHarness.Stage("second fake", (tupleExpr, dataset, bindings) -> {
					assertNotSame(firstOptimizerInput.get(), root.getArg());
					assertEquals(101, root.getArg().getOptimizationTag());
					secondOptimizerInput.set(root.getArg());
					root.getArg().setOptimizationTag(202);
				}));

		new TupleExprJsonOptimizerRoundTripHarness().run(root, null, EmptyBindingSet.getInstance(), stages,
				"fake optimizer feed-forward test",
				(importedRoot, checkpoint) -> importedChildren.add(importedRoot.getArg()));

		assertEquals(3, importedChildren.size());
		assertNotSame(importedChildren.get(0), importedChildren.get(1));
		assertNotSame(importedChildren.get(1), importedChildren.get(2));
		assertNotSame(secondOptimizerInput.get(), root.getArg());
		assertEquals(202, root.getArg().getOptimizationTag());
	}
}
